use Twilio\Rest\Client;
use Illuminate\Support\Facades\Log;

class TwilioSmsService
{
    protected Client $twilioClient;
    protected string $twilioFromNumber;

    public function __construct()
    {
        $accountSid = config('services.twilio.sid');
        $authToken = config('services.twilio.token');
        $this->twilioFromNumber = config('services.twilio.from');

        if (empty($accountSid) || empty($authToken) || empty($this->twilioFromNumber)) {
            Log::error('Twilio credentials are not fully configured. Please check TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, and TWILIO_PHONE_NUMBER in your .env file.');
            throw new \RuntimeException('Twilio service is not properly configured.');
        }

        $this->twilioClient = new Client($accountSid, $authToken);
    }

    /**
     * Sends an SMS message using Twilio.
     *
     * @param string $to The recipient's phone number (e.g., "+15551234567").
     * @param string $message The body of the SMS message.
     * @throws \Twilio\Exceptions\TwilioException If the message sending fails.
     * @return \Twilio\Rest\Api\V2010\Account\MessageInstance
     */
    public function sendSms(string $to, string $message): \Twilio\Rest\Api\V2010\Account\MessageInstance
    {
        try {
            $sms = $this->twilioClient->messages->create(
                $to,
                [
                    'from' => $this->twilioFromNumber,
                    'body' => $message,
                ]
            );

            Log::info("SMS sent successfully to {$to}. SID: {$sms->sid}");
            return $sms;
        } catch (\Twilio\Exceptions\TwilioException $e) {
            Log::error("Failed to send SMS to {$to}: " . $e->getMessage());
            throw $e; // Re-throw the exception for the calling code to handle
        }
    }
}

